const assert = require("node:assert/strict");
const fs = require("node:fs");
const vm = require("node:vm");

const tests = [];

function test(name, fn) {
  tests.push({ name, fn });
}

function loadPocketLedger() {
  const html = fs.readFileSync("index.html", "utf8");
  const scripts = [...html.matchAll(/<script>([\s\S]*?)<\/script>/g)].map((match) => match[1]);
  const appScript = scripts.find((script) => script.includes("window.PocketLedger"));

  assert.ok(appScript, "index.html should expose window.PocketLedger for behavior tests");

  const context = {
    console,
    Intl,
    Date,
    Math,
    window: {},
    document: { addEventListener() {} },
    localStorage: {
      getItem() {
        return null;
      },
      setItem() {},
    },
  };

  vm.createContext(context);
  vm.runInContext(appScript, context);
  return context.window.PocketLedger;
}

test("normalizes a EUR amount to integer cents", () => {
  const ledger = loadPocketLedger();

  const expense = ledger.normalizeExpense(
    { amount: "12.30", category: " Groceries ", date: "2026-07-08", note: " lunch " },
    () => "fixed-id",
    () => "2026-07-08T10:00:00.000Z",
  );

  assert.equal(expense.id, "fixed-id");
  assert.equal(expense.amountCents, 1230);
  assert.equal(expense.category, "Groceries");
  assert.equal(expense.note, "lunch");
});

test("sums only expenses from the requested month", () => {
  const ledger = loadPocketLedger();

  const total = ledger.totalForMonth(
    [
      { date: "2026-07-01", amountCents: 450 },
      { date: "2026-07-31", amountCents: 1550 },
      { date: "2026-06-30", amountCents: 9999 },
    ],
    "2026-07",
  );

  assert.equal(total, 2000);
});

test("groups current-month totals by category", () => {
  const ledger = loadPocketLedger();

  const totals = ledger.categoryTotalsForMonth(
    [
      { date: "2026-07-01", category: "Groceries", amountCents: 450 },
      { date: "2026-07-02", category: "Transport", amountCents: 800 },
      { date: "2026-07-03", category: "Groceries", amountCents: 1550 },
      { date: "2026-06-30", category: "Groceries", amountCents: 9999 },
    ],
    "2026-07",
  );

  assert.deepEqual(
    Array.from(totals, ({ category, amountCents }) => ({ category, amountCents })),
    [
      { category: "Groceries", amountCents: 2000 },
      { category: "Transport", amountCents: 800 },
    ],
  );
});

test("serializes expenses to CSV with headers and escaped fields", () => {
  const ledger = loadPocketLedger();

  const csv = ledger.expensesToCsv([
    {
      date: "2026-07-08",
      category: "Groceries, weekly",
      note: 'He said "fresh"\nand left',
      amountCents: 1230,
    },
    {
      date: "2026-07-07",
      category: "Transport",
      note: "",
      amountCents: 500,
    },
  ]);

  assert.equal(
    csv,
    'Date,Category,Note,Amount EUR\r\n2026-07-08,"Groceries, weekly","He said ""fresh""\nand left",12.30\r\n2026-07-07,Transport,,5.00',
  );
});
test("falls back to an empty list for malformed storage", () => {
  const ledger = loadPocketLedger();

  assert.equal(ledger.parseStoredExpenses("not json").length, 0);
  assert.equal(ledger.parseStoredExpenses('{"not":"an array"}').length, 0);
});

test("adds and deletes an expense through the page event handlers", () => {
  const html = fs.readFileSync("index.html", "utf8");
  const scripts = [...html.matchAll(/<script>([\s\S]*?)<\/script>/g)].map((match) => match[1]);
  const appScript = scripts.find((script) => script.includes("window.PocketLedger"));
  const storage = new Map();
  const listeners = {};
  const elements = {};

  function element(id) {
    elements[id] = {
      id,
      value: "",
      textContent: "",
      innerHTML: "",
      style: {},
      listeners: {},
      dataset: {},
      addEventListener(type, handler) {
        this.listeners[type] = handler;
      },
      focus() {},
    };
    return elements[id];
  }

  [
    "expense-form",
    "amount",
    "category",
    "date",
    "note",
    "form-error",
    "expense-rows",
    "table-wrap",
    "empty-state",
    "expense-count",
    "month-total",
    "month-label",
    "category-filter",
    "category-totals",
    "csv-export",
  ].forEach(element);

  elements["expense-form"].reset = () => {
    elements.amount.value = "";
    elements.category.value = "";
    elements.date.value = "";
    elements.note.value = "";
  };

  class FakeFormData {
    entries() {
      return [
        ["amount", elements.amount.value],
        ["category", elements.category.value],
        ["date", elements.date.value],
        ["note", elements.note.value],
      ];
    }
  }

  const context = {
    console,
    FormData: FakeFormData,
    Intl,
    Date,
    Math,
    window: {},
    document: {
      addEventListener(type, handler) {
        listeners[type] = handler;
      },
      getElementById(id) {
        return elements[id];
      },
    },
    localStorage: {
      getItem(key) {
        return storage.has(key) ? storage.get(key) : null;
      },
      setItem(key, value) {
        storage.set(key, value);
      },
    },
  };

  vm.createContext(context);
  vm.runInContext(appScript, context);
  listeners.DOMContentLoaded();

  elements.amount.value = "12.30";
  elements.category.value = "Groceries";
  elements.date.value = "2026-07-08";
  elements.note.value = "Lunch";
  elements["expense-form"].listeners.submit({ preventDefault() {} });

  const saved = JSON.parse(storage.get(context.window.PocketLedger.STORAGE_KEY));
  assert.equal(saved.length, 1);
  assert.equal(saved[0].amountCents, 1230);
  assert.match(elements["month-total"].textContent, /12[,.]30/);
  assert.equal(elements["expense-count"].textContent, "1 item");

  elements["expense-rows"].listeners.click({
    target: {
      closest() {
        return { dataset: { deleteId: saved[0].id } };
      },
    },
  });

  assert.equal(JSON.parse(storage.get(context.window.PocketLedger.STORAGE_KEY)).length, 0);
  assert.equal(elements["expense-count"].textContent, "0 items");
  assert.equal(elements["empty-state"].style.display, "block");
});

